mapper.select:
SELECT * FROM payment 
WHERE created_at >= #{startDate} 
AND created_at <= #{endDate}
AND status = 1

SELECT COUNT(*) FROM payment 
WHERE created_at >= #{startDate} 
AND created_at <= #{endDate}
AND status = 1

SELECT COALESCE(SUM(p.amount), 0)
FROM payment p

    INNER JOIN parking_record pr ON p.parking_record_id = pr.id

WHERE p.created_at >= #{startDate}
AND p.created_at <= #{endDate}
AND p.status = 1

    AND pr.parking_lot_id = #{parkingLotId}

SELECT COUNT(*)
FROM payment p

    INNER JOIN parking_record pr ON p.parking_record_id = pr.id

WHERE p.created_at >= #{startDate}
AND p.created_at <= #{endDate}
AND p.status = 1

    AND pr.parking_lot_id = #{parkingLotId}

SELECT p.id, pl.name as parkingLotName, v.plate_number as plateNumber, p.amount, p.payment_method as paymentMethod, p.transaction_id as transactionId, p.created_at as createdAt FROM payment p INNER JOIN parking_record pr ON p.parking_record_id = pr.id INNER JOIN parking_lot pl ON pr.parking_lot_id = pl.id INNER JOIN vehicle v ON pr.vehicle_id = v.id WHERE p.status = 1
AND pr.parking_lot_id = #{parkingLotId}
AND v.plate_number LIKE CONCAT('%', #{plateNumber}, '%')
AND p.payment_method = #{paymentMethod}
AND p.created_at >= #{startDate}
AND p.created_at <= #{endDate}
ORDER BY p.created_at DESC LIMIT #{offset}, #{pageSize}

SELECT COUNT(*)
FROM payment p
INNER JOIN parking_record pr ON p.parking_record_id = pr.id
INNER JOIN vehicle v ON pr.vehicle_id = v.id
WHERE p.status = 1

    AND pr.parking_lot_id = #{parkingLotId}


    AND v.plate_number LIKE CONCAT('%', #{plateNumber}, '%')


    AND p.payment_method = #{paymentMethod}


    AND p.created_at >= #{startDate}


    AND p.created_at <= #{endDate}

SELECT COUNT(DISTINCT pr.vehicle_id)
FROM payment p
INNER JOIN parking_record pr ON p.parking_record_id = pr.id
WHERE p.created_at >= #{startDate}
AND p.created_at <= #{endDate}
AND p.status = 1

    AND pr.parking_lot_id = #{parkingLotId}
